create or replace function public.create_stock_transfer(p_organization_id uuid,p_branch_id uuid,p_source_warehouse_id uuid,p_destination_warehouse_id uuid,p_transfer_date date,p_notes text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; line jsonb; v_product uuid; v_qty numeric; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient inventory permission'; end if; if p_source_warehouse_id=p_destination_warehouse_id then raise exception 'Warehouses must be different'; end if; if not exists(select 1 from public.warehouses where id=p_source_warehouse_id and organization_id=p_organization_id and is_active) or not exists(select 1 from public.warehouses where id=p_destination_warehouse_id and organization_id=p_organization_id and is_active) then raise exception 'Warehouse not found'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Transfer requires lines'; end if; v_no:=public.next_document_number(p_organization_id,'TRF'); insert into public.stock_transfers(organization_id,branch_id,transfer_number,source_warehouse_id,destination_warehouse_id,transfer_date,status,notes,created_by,approved_by) values(p_organization_id,p_branch_id,v_no,p_source_warehouse_id,p_destination_warehouse_id,coalesce(p_transfer_date,current_date),'approved',nullif(trim(p_notes),''),p_actor_id,p_actor_id) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop v_product:=(line->>'productId')::uuid; v_qty:=coalesce((line->>'quantity')::numeric,0); if v_qty<=0 or not exists(select 1 from public.products where id=v_product and organization_id=p_organization_id and is_active) then raise exception 'Invalid transfer line'; end if; if coalesce((select quantity from public.stock_balances where organization_id=p_organization_id and product_id=v_product and warehouse_id=p_source_warehouse_id),0)<v_qty then raise exception 'Insufficient stock for transfer'; end if; insert into public.stock_transfer_items(organization_id,stock_transfer_id,product_id,quantity) values(p_organization_id,v_id,v_product,v_qty); end loop; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.transfer.approved','stock_transfer',v_id,jsonb_build_object('number',v_no)); return jsonb_build_object('id',v_id,'number',v_no); end $$;

create or replace function public.complete_stock_transfer(p_organization_id uuid,p_stock_transfer_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare t public.stock_transfers%rowtype; i public.stock_transfer_items%rowtype; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','manager']::public.app_role[]) then raise exception 'Insufficient inventory permission'; end if; select * into t from public.stock_transfers where id=p_stock_transfer_id and organization_id=p_organization_id for update; if not found or t.status not in ('approved','in_transit') then raise exception 'Transfer is not ready to complete'; end if; for i in select * from public.stock_transfer_items where stock_transfer_id=t.id order by created_at loop perform public.record_stock_movement(p_organization_id,i.product_id,t.source_warehouse_id,'transfer_out',i.quantity,t.transfer_number,p_actor_id,'stock_transfer',t.id); perform public.record_stock_movement(p_organization_id,i.product_id,t.destination_warehouse_id,'transfer_in',i.quantity,t.transfer_number,p_actor_id,'stock_transfer',t.id); end loop; update public.stock_transfers set status='completed',completed_by=p_actor_id,completed_at=now(),updated_at=now() where id=t.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.transfer.completed','stock_transfer',t.id,jsonb_build_object('number',t.transfer_number)); return jsonb_build_object('id',t.id,'number',t.transfer_number); end $$;

create or replace function public.post_inventory_adjustment(p_organization_id uuid,p_branch_id uuid,p_warehouse_id uuid,p_product_id uuid,p_adjustment_type text,p_quantity numeric,p_adjustment_date date,p_reason text,p_source_count_id uuid,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare v_id uuid; v_no text; v_journal uuid; v_journal_no text; v_cost numeric; v_value numeric; v_inventory uuid; v_expense uuid; v_movement public.stock_movement_type; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','inventory','accountant']::public.app_role[]) then raise exception 'Insufficient inventory adjustment permission'; end if; if p_adjustment_type not in ('increase','decrease') or p_quantity<=0 then raise exception 'Invalid adjustment'; end if; select cost_price into v_cost from public.products where id=p_product_id and organization_id=p_organization_id and is_active; if not found then raise exception 'Product not found'; end if; if not exists(select 1 from public.warehouses where id=p_warehouse_id and organization_id=p_organization_id and is_active) then raise exception 'Warehouse not found'; end if; select id into v_inventory from public.accounts where organization_id=p_organization_id and code='1200'; select id into v_expense from public.accounts where organization_id=p_organization_id and code='6000'; if v_inventory is null or v_expense is null then raise exception 'Inventory accounts are missing'; end if; v_no:=public.next_document_number(p_organization_id,'ADJ'); v_journal_no:=public.next_document_number(p_organization_id,'JE'); v_value:=round(p_quantity*coalesce(v_cost,0),2); v_movement:=case when p_adjustment_type='increase' then 'adjustment_in'::public.stock_movement_type else 'adjustment_out'::public.stock_movement_type end; perform public.record_stock_movement(p_organization_id,p_product_id,p_warehouse_id,v_movement,p_quantity,v_no,p_actor_id,'inventory_adjustment',null); insert into public.journal_entries(organization_id,branch_id,entry_number,entry_date,memo,status,source_type,created_by) values(p_organization_id,p_branch_id,v_journal_no,coalesce(p_adjustment_date,current_date),'Inventory adjustment '||v_no,'draft','inventory_adjustment',p_actor_id) returning id into v_journal; if v_value>0 then if p_adjustment_type='increase' then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_inventory,p_reason,v_value,0),(p_organization_id,v_journal,v_expense,'Inventory gain / correction',0,v_value); else insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_expense,p_reason,v_value,0),(p_organization_id,v_journal,v_inventory,'Inventory reduction',0,v_value); end if; end if; insert into public.inventory_adjustments(organization_id,branch_id,warehouse_id,product_id,adjustment_number,adjustment_date,adjustment_type,quantity,unit_cost,reason,source_count_id,journal_entry_id,created_by) values(p_organization_id,p_branch_id,p_warehouse_id,p_product_id,v_no,coalesce(p_adjustment_date,current_date),p_adjustment_type,p_quantity,coalesce(v_cost,0),trim(p_reason),p_source_count_id,v_journal,p_actor_id) returning id into v_id; update public.stock_movements set source_id=v_id where organization_id=p_organization_id and reference=v_no and source_type='inventory_adjustment' and source_id is null; update public.journal_entries set status='posted',source_id=v_id,posted_by=p_actor_id,posted_at=now() where id=v_journal; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'inventory.adjustment.posted','inventory_adjustment',v_id,jsonb_build_object('number',v_no,'quantity',p_quantity,'type',p_adjustment_type)); return jsonb_build_object('id',v_id,'number',v_no,'value',v_value); end $$;

revoke all on function public.create_stock_transfer(uuid,uuid,uuid,uuid,date,text,jsonb,uuid) from public; grant execute on function public.create_stock_transfer(uuid,uuid,uuid,uuid,date,text,jsonb,uuid) to authenticated;
revoke all on function public.complete_stock_transfer(uuid,uuid,uuid) from public; grant execute on function public.complete_stock_transfer(uuid,uuid,uuid) to authenticated;
revoke all on function public.post_inventory_adjustment(uuid,uuid,uuid,uuid,text,numeric,date,text,uuid,uuid) from public; grant execute on function public.post_inventory_adjustment(uuid,uuid,uuid,uuid,text,numeric,date,text,uuid,uuid) to authenticated;